use regex::Regex;

struct WebhookDispatcher {
    compiled_regex: Regex,
}

impl WebhookDispatcher {
    fn new(pattern: &str) -> Result<Self, regex::Error> {
        Ok(WebhookDispatcher { compiled_regex: Regex::new(pattern)? })
    }

    fn extract_payload(&self, raw_data: &str) -> Option<String> {
        self.compiled_regex.find(raw_data).map(|m| m.as_str().to_owned())
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let pattern = r"status:(d+);payload=(.*?)(?=s*|$|bretries:d+)";
    let dispatcher = WebhookDispatcher::new(pattern)?;

    let data1 = "timestamp=123;status:200;payload={\"key\":\"value\"};retries:1";
    let data2 = "error_code=500;message=\"Failed to process\"";
    let data3 = "status:404;payload=No match here";

    if let Some(extracted) = dispatcher.extract_payload(data1) {
        println!("Extracted from data 1: {}", extracted);
    }

    if let Some(extracted) = dispatcher.extract_payload(data2) {
        println!("Extracted from data 2: {}", extracted);
    }

    if let Some(extracted) = dispatcher.extract_payload(data3) {
        println!("Extracted from data 3: {}", extracted);
    }

    Ok(())
}

use regex::Regex;

struct ConfigBlock {
    name: String,
    pattern_regex: Regex,
}

fn load_config_block(name: &str, pattern_string: &str) -> Result<ConfigBlock, Box<dyn std::error::Error>> {
    let compiled = Regex::new(pattern_string)?;
    Ok(ConfigBlock {
        name: name.to_string(),
        pattern_regex: compiled,
    })
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let block1 = load_config_block("API Endpoint", r"^s*http:\/\/.*?s*$").unwrap();
    println!("Successfully compiled pattern for block: {}", block1.name);
    if block1.pattern_regex.is_match("  http://api.example.com  ") {
        println!("Match found on test string.");
    }

    let block2 = load_config_block("Version Tag", r"^vd+\.d+\.d+$").unwrap();
    println!("Successfully compiled pattern for block: {}", block2.name);

    Ok(())
}

use std::error::Error;
use std::fs::File;
use std::io::{self, Write, Read};
use regex::Regex;

fn main() -> Result<(), Box<dyn Error>> {
    let file_path = "config.txt";
    let mut file = File::create(file_path)?;
    writeln!(file, "model_name = ResNet50")?;
    writeln!(file, "batch_size = 32")?;
    writeln!(file, "learning_rate = 0.001")?;
    writeln!(file, "optimizer = Adam")?;
    drop(file);

    let mut file = File::open(file_path)?;
    let mut contents = String::new();
    file.read_to_string(&mut contents)?;

    let re = Regex::new(r"(w+)s*=s*(.+)")?;

    println!("n--- Extracted Configuration ---n");

    for cap in re.captures_iter(&contents) {
        let key = &cap[1];
        let value = &cap[2].trim();
        println!("Key: {}", key);
        println!("Value: {}", value);
    }

    Ok(())
}

