use regex::Regex;

fn main() {
    let id_pattern = "^[0-9]{9}$";
    let compiled_regex = match Regex::new(id_pattern) {
        Ok(r) => r,
        Err(e) => panic!("Failed to compile regex: {}", e),
    };

    let test_ids = vec![
        String::from("123456789"), 
        String::from("ABCDEFGHI"), 
        String::from("12345678"),
        String::from("1234567890"),
    ];

    for id in test_ids {
        if compiled_regex.is_match(&id) {
            println!("\"{}\": Matches the required pattern.", id);
        } else {
            println!("\"{}\": Does not match the required pattern.", id);
        }
    }
}
